import ldap3

def search_user(username, server, user_dn, password):
    try:
        server = ldap3.Server(server)
        conn = ldap3.Connection(server, user=user_dn, password=password, auto_bind=True)
        query = f"(uid={username})"
        attributes = ['cn', 'mail']
        conn.search(search_base='dc=example,dc=com',
                    search_filter=query,
                    attributes=attributes)
        
        if conn.entries:
            return conn.entries[0].cn.value
        else:
            return None
    
    except ldap3.core.exceptions.LDAPSocketOpenError as e:
        print(f"LDAP connection error: {e}")
        return None

    finally:
        try:
            conn.unbind()
        except Exception as e:
            print(f"Failed to unbind LDAP connection: {e}")

